from __future__ import annotations
import json
from textwrap import dedent
from typing import Any, Sequence
from app.llm.base_client import BaseLLMClient, ChatMessage, ModelCapabilities, ModelResponse
from app.llm.model_config import RoleModelConfig
from app.llm.providers.gemini_client import GeminiNativeClient
from app.llm.providers.mistral_client import MistralClient
from app.llm.providers.openai_compatible_client import OpenAICompatibleClient

class MockLLMClient(BaseLLMClient):
    """Deterministic fallback client that keeps the system runnable without external APIs."""

    def __init__(self, config: RoleModelConfig) -> None:
        super().__init__(capabilities=ModelCapabilities(supports_tools=False, supports_json=False, supports_system_prompt=True, max_context=32768))
        self.config = config

    def generate(self, messages: Sequence[ChatMessage], tools: Sequence[dict[str, Any]] | None=None, response_format: dict[str, Any] | None=None, temperature: float | None=None, max_tokens: int | None=None, **kwargs: Any) -> ModelResponse:
        _ = (tools, response_format, temperature, max_tokens, kwargs)
        context = self._extract_context(messages)
        generators = {'requirement_analyzer': self._requirements, 'architect': self._architecture, 'planning_reviewer': self._planning_review, 'coder': self._coding, 'reviewer': self._review, 'test_writer': self._test_writer, 'parameter_solver': self._parameter_solver, 'parameter_repairer': self._parameter_repairer}
        generator = generators.get(self.config.role)
        if generator is None:
            raise ValueError(f'Unsupported role for mock client: {self.config.role}')
        text = generator(context)
        return ModelResponse(text=text, raw={'role': self.config.role, 'messages': list(messages)})

    @staticmethod
    def _extract_context(messages: Sequence[ChatMessage]) -> dict[str, str]:
        context: dict[str, str] = {}
        for message in messages:
            if message.role != 'user':
                continue
            for line in message.content.splitlines():
                if ': ' not in line:
                    continue
                key, value = line.split(': ', 1)
                context[key.strip()] = value.strip()
        return context

    def _requirements(self, context: dict[str, str]) -> str:
        task = context.get('user_task', 'unknown task')
        return dedent(f'\n            Goal:\n            - Deliver a project-level code generation workflow for the task: {task}\n\n            Functional requirements:\n            - Analyze the task and derive implementation requirements.\n            - Produce an architecture plan before coding.\n            - Support iterative coding, review, and test-driven correction loops.\n            - Persist workflow artifacts for later inspection.\n\n            Non-functional requirements:\n            - Keep the architecture model-agnostic.\n            - Use modular Python components with strong typing and simple logging.\n            - Make the workflow observable through shared graph state.\n            ').strip()

    def _architecture(self, context: dict[str, str]) -> str:
        iteration = int(context.get('planning_iteration', '1'))
        feedback = context.get('planning_feedback', '').strip()
        base = dedent('\n            Components:\n            - Supervisor for workflow bootstrap and coordination.\n            - Requirement Analyzer, Architect, Coder, Reviewer, Test Writer, and Test Runner roles.\n            - Shared GraphState carrying artifacts, statuses, and iteration counters.\n            - LLM registry/factory layer that decouples role logic from providers.\n\n            Data Flow:\n            - The graph starts from supervision and requirement analysis, moves into planning, then coding/review, then tests.\n            - Test outcomes route the workflow back to coding or architecture when needed.\n\n            Iteration Strategy:\n            - Local planning loop bounded by max_planning_iterations.\n            - Local coding loop bounded by max_coding_iterations.\n            - Global test loop bounded by max_global_iterations.\n\n            Failure Handling:\n            - Route implementation bugs back to the coder.\n            - Route structural issues back to the architect.\n            - Mark the run incomplete when the global limit is exhausted.\n            ').strip()
        if iteration == 1 and (not feedback):
            return base + '\n\nOpen risks:\n- Testing strategy is minimal in the first draft.'
        return base + dedent('\n\n            Quality refinements:\n            - Planning feedback has been incorporated.\n            - Artifact persistence uses workspace-local files for reproducibility.\n            - The design is ready for swapping mock clients with real provider clients.\n            ').strip()

    def _planning_review(self, context: dict[str, str]) -> str:
        iteration = int(context.get('planning_iteration', '1'))
        if iteration < 2:
            return dedent('\n                Changes requested:\n                - Expand the testing and artifact persistence strategy.\n                - Clarify how routing distinguishes implementation bugs from architecture issues.\n                ').strip()
        return dedent('\n            Approved:\n            - The plan covers components, data flow, iteration limits, and failure handling.\n            - The routing and artifact strategy are sufficiently clear for implementation.\n            ').strip()

    def _coding(self, context: dict[str, str]) -> str:
        iteration = int(context.get('coding_iteration', '1'))
        reviewer_feedback = context.get('reviewer_feedback', '').strip()
        test_status = context.get('test_status', 'not_run')
        summary = dedent(f"\n            ## Implementation Summary\n\n            This coding pass writes a real Python CLI TODO application with JSON persistence and pytest coverage.\n\n            Current cycle details:\n            - coding_iteration={iteration}\n            - previous_reviewer_feedback={reviewer_feedback or 'none'}\n            - previous_test_status={test_status}\n\n            Architecture alignment:\n            - `todo/models.py` contains the task model.\n            - `todo/repository.py` handles JSON persistence.\n            - `todo/service.py` encapsulates business logic and validation.\n            - `todo/main.py` exposes the CLI entrypoint with argparse.\n            - `tests/` contains repository and service tests.\n            ").strip()
        payload = {'summary': summary, 'files': [{'path': 'todo/__init__.py', 'content': "__all__ = ['models', 'repository', 'service', 'main']\n"}, {'path': 'todo/models.py', 'content': dedent('\n                        from __future__ import annotations\n\n                        from dataclasses import asdict, dataclass\n\n\n                        @dataclass(slots=True)\n                        class Task:\n                            id: int\n                            description: str\n                            completed: bool = False\n\n                            def to_dict(self) -> dict[str, object]:\n                                return asdict(self)\n                        ').strip() + '\n'}, {'path': 'todo/repository.py', 'content': dedent('\n                        from __future__ import annotations\n\n                        import json\n                        from json import JSONDecodeError\n                        from pathlib import Path\n\n                        from todo.models import Task\n\n\n                        class TaskRepository:\n                            def __init__(self, storage_path: str | Path = "tasks.json") -> None:\n                                self.storage_path = Path(storage_path)\n\n                            def load(self) -> list[Task]:\n                                if not self.storage_path.exists():\n                                    return []\n                                try:\n                                    raw_items = json.loads(self.storage_path.read_text(encoding="utf-8"))\n                                except JSONDecodeError:\n                                    return []\n                                return [Task(**item) for item in raw_items]\n\n                            def save(self, tasks: list[Task]) -> None:\n                                self.storage_path.write_text(\n                                    json.dumps([task.to_dict() for task in tasks], indent=2),\n                                    encoding="utf-8",\n                                )\n                        ').strip() + '\n'}, {'path': 'todo/service.py', 'content': dedent('\n                        from __future__ import annotations\n\n                        from todo.models import Task\n                        from todo.repository import TaskRepository\n\n\n                        class TaskNotFoundError(ValueError):\n                            pass\n\n\n                        class TodoService:\n                            def __init__(self, repository: TaskRepository) -> None:\n                                self.repository = repository\n\n                            def list_tasks(self) -> list[Task]:\n                                return self.repository.load()\n\n                            def add_task(self, description: str) -> Task:\n                                cleaned = description.strip()\n                                if not cleaned:\n                                    raise ValueError("Task description cannot be empty.")\n                                tasks = self.repository.load()\n                                next_id = max((task.id for task in tasks), default=0) + 1\n                                task = Task(id=next_id, description=cleaned)\n                                tasks.append(task)\n                                self.repository.save(tasks)\n                                return task\n\n                            def complete_task(self, task_id: int) -> Task:\n                                tasks = self.repository.load()\n                                task = self._find_task(tasks, task_id)\n                                task.completed = True\n                                self.repository.save(tasks)\n                                return task\n\n                            def delete_task(self, task_id: int) -> None:\n                                tasks = self.repository.load()\n                                task = self._find_task(tasks, task_id)\n                                tasks.remove(task)\n                                self.repository.save(tasks)\n\n                            def clear_completed(self) -> int:\n                                tasks = self.repository.load()\n                                remaining = [task for task in tasks if not task.completed]\n                                removed = len(tasks) - len(remaining)\n                                self.repository.save(remaining)\n                                return removed\n\n                            @staticmethod\n                            def _find_task(tasks: list[Task], task_id: int) -> Task:\n                                for task in tasks:\n                                    if task.id == task_id:\n                                        return task\n                                raise TaskNotFoundError(f"Task {task_id} does not exist.")\n                        ').strip() + '\n'}, {'path': 'todo/main.py', 'content': dedent('\n                        from __future__ import annotations\n\n                        import argparse\n\n                        from todo.repository import TaskRepository\n                        from todo.service import TaskNotFoundError, TodoService\n\n\n                        def build_parser() -> argparse.ArgumentParser:\n                            parser = argparse.ArgumentParser(description="CLI TODO application")\n                            subparsers = parser.add_subparsers(dest="command")\n\n                            add_parser = subparsers.add_parser("add", help="Add a task")\n                            add_parser.add_argument("description")\n\n                            subparsers.add_parser("list", help="List tasks")\n\n                            done_parser = subparsers.add_parser("done", help="Mark a task as completed")\n                            done_parser.add_argument("task_id", type=int)\n\n                            remove_parser = subparsers.add_parser("remove", help="Delete a task")\n                            remove_parser.add_argument("task_id", type=int)\n\n                            subparsers.add_parser("clear-completed", help="Remove completed tasks")\n                            return parser\n\n\n                        def main() -> int:\n                            parser = build_parser()\n                            args = parser.parse_args()\n                            service = TodoService(TaskRepository())\n\n                            try:\n                                if args.command == "add":\n                                    task = service.add_task(args.description)\n                                    print(f"Task {task.id} added: {task.description}")\n                                    return 0\n                                if args.command == "list":\n                                    for task in service.list_tasks():\n                                        status = "x" if task.completed else " "\n                                        print(f"[{status}] {task.id}: {task.description}")\n                                    return 0\n                                if args.command == "done":\n                                    task = service.complete_task(args.task_id)\n                                    print(f"Task {task.id} marked as done.")\n                                    return 0\n                                if args.command == "remove":\n                                    service.delete_task(args.task_id)\n                                    print(f"Task {args.task_id} removed.")\n                                    return 0\n                                if args.command == "clear-completed":\n                                    removed = service.clear_completed()\n                                    print(f"Removed {removed} completed task(s).")\n                                    return 0\n                                parser.print_help()\n                                return 0\n                            except (ValueError, TaskNotFoundError) as exc:\n                                print(str(exc))\n                                return 1\n\n\n                        if __name__ == "__main__":\n                            raise SystemExit(main())\n                        ').strip() + '\n'}, {'path': 'tests/test_service.py', 'content': dedent('\n                        from __future__ import annotations\n\n                        from pathlib import Path\n\n                        from todo.repository import TaskRepository\n                        from todo.service import TaskNotFoundError, TodoService\n\n\n                        def build_service(tmp_path: Path) -> TodoService:\n                            return TodoService(TaskRepository(tmp_path / "tasks.json"))\n\n\n                        def test_add_task_assigns_incremental_id(tmp_path: Path) -> None:\n                            service = build_service(tmp_path)\n                            first = service.add_task("Buy milk")\n                            second = service.add_task("Write tests")\n                            assert first.id == 1\n                            assert second.id == 2\n\n\n                        def test_complete_task_marks_task_done(tmp_path: Path) -> None:\n                            service = build_service(tmp_path)\n                            task = service.add_task("Ship feature")\n                            updated = service.complete_task(task.id)\n                            assert updated.completed is True\n\n\n                        def test_delete_task_removes_task(tmp_path: Path) -> None:\n                            service = build_service(tmp_path)\n                            task = service.add_task("Temporary task")\n                            service.delete_task(task.id)\n                            assert service.list_tasks() == []\n\n\n                        def test_clear_completed_removes_only_completed_tasks(tmp_path: Path) -> None:\n                            service = build_service(tmp_path)\n                            first = service.add_task("Done")\n                            second = service.add_task("Pending")\n                            service.complete_task(first.id)\n                            removed = service.clear_completed()\n                            remaining = service.list_tasks()\n                            assert removed == 1\n                            assert len(remaining) == 1\n                            assert remaining[0].description == "Pending"\n                            assert remaining[0].completed is False\n\n\n                        def test_missing_task_raises_error(tmp_path: Path) -> None:\n                            service = build_service(tmp_path)\n                            try:\n                                service.complete_task(99)\n                            except TaskNotFoundError:\n                                assert True\n                            else:\n                                assert False, "Expected TaskNotFoundError"\n                        ').strip() + '\n'}, {'path': 'tests/test_repository.py', 'content': dedent('\n                        from __future__ import annotations\n\n                        from pathlib import Path\n\n                        from todo.models import Task\n                        from todo.repository import TaskRepository\n\n\n                        def test_repository_roundtrip(tmp_path: Path) -> None:\n                            repo = TaskRepository(tmp_path / "tasks.json")\n                            repo.save([Task(id=1, description="Buy milk"), Task(id=2, description="Write tests")])\n                            loaded = repo.load()\n                            assert len(loaded) == 2\n                            assert loaded[0].description == "Buy milk"\n                            assert loaded[1].id == 2\n\n\n                        def test_repository_handles_missing_file(tmp_path: Path) -> None:\n                            repo = TaskRepository(tmp_path / "missing.json")\n                            assert repo.load() == []\n\n\n                        def test_repository_handles_corrupted_json(tmp_path: Path) -> None:\n                            path = tmp_path / "tasks.json"\n                            path.write_text("{not-valid-json}", encoding="utf-8")\n                            repo = TaskRepository(path)\n                            assert repo.load() == []\n                        ').strip() + '\n'}]}
        return json.dumps(payload, ensure_ascii=True)

    def _review(self, context: dict[str, str]) -> str:
        iteration = int(context.get('coding_iteration', '1'))
        if iteration < 2:
            return dedent('\n                Changes requested:\n                - Make the testing plan explicit in the implementation summary.\n                - Confirm that artifacts are written to stable workspace paths.\n                ').strip()
        return dedent('\n            Approved:\n            - The implementation summary covers architecture alignment, artifact persistence, and test execution.\n            - The coding pass is sufficient to proceed to test execution.\n            ').strip()

    def _test_writer(self, context: dict[str, str]) -> str:
        _ = context
        return json.dumps({'summary': 'Generated generic smoke tests for project structure and importability.', 'files': [{'path': 'tests/test_generated_smoke.py', 'content': "from pathlib import Path\n\n\ndef test_project_contains_files():\n    root = Path(__file__).resolve().parents[1]\n    files = [p for p in root.rglob('*') if p.is_file() and '__pycache__' not in p.parts]\n    assert files\n\n\ndef test_python_sources_compile():\n    import py_compile\n    root = Path(__file__).resolve().parents[1]\n    for path in root.rglob('*.py'):\n        if '__pycache__' in path.parts:\n            continue\n        py_compile.compile(str(path), doraise=True)\n"}]})

    def _parameter_solver(self, context: dict[str, str]) -> str:
        _ = context
        return json.dumps({'parameters': []})

    def _parameter_repairer(self, context: dict[str, str]) -> str:
        _ = context
        return json.dumps({'parameters': []})

class LLMRegistry:

    def __init__(self) -> None:
        self._providers: dict[str, type[BaseLLMClient]] = {'mock': MockLLMClient, 'gemini_native': GeminiNativeClient, 'openai_compatible': OpenAICompatibleClient, 'mistral': MistralClient}

    def register(self, provider: str, client_cls: type[BaseLLMClient]) -> None:
        self._providers[provider] = client_cls

    def create(self, config: RoleModelConfig) -> BaseLLMClient:
        client_cls = self._providers.get(config.provider)
        if client_cls is None:
            raise ValueError(f"Provider '{config.provider}' is not registered. Register a concrete client in LLMRegistry before use.")
        return client_cls(config)